    {
      "text": "सफलतापूर्वक संकलित होता है",
      "hint": "संदर्भों वाले स्ट्रक्ट्स को लाइफ़टाइम एनोटेशन की आवश्यकता होती है"
    },
    {
      "text": "त्रुटि: लाइफ़टाइम निर्दिष्टकर्ता गायब है"
    },
    {
      "text": "त्रुटि: लाइफ़टाइम असंगति",
      "hint": "हमने अभी तक कोई लाइफ़टाइम निर्दिष्ट नहीं किया है"
    },
    {
      "text": "त्रुटि: अमान्य संदर्भ",
      "hint": "संदर्भ वैध हैं, लेकिन कुछ और गायब है"
    }
